// =============================================================================
// Core User & Authentication Types
// =============================================================================

export interface AuthUser {
  readonly id: string;
  readonly email: string;
  readonly role: UserRole;
  readonly permissions: Permission[];
  readonly profile: UserProfile;
  readonly onboardingStatus: OnboardingStatus;
  readonly createdAt: Date;
  readonly lastLoginAt: Date | null;
}

export type UserRole = 'admin' | 'manager' | 'operator' | 'viewer';

export interface Permission {
  readonly resource: string;
  readonly actions: ('create' | 'read' | 'update' | 'delete')[];
  readonly conditions?: Record<string, any>;
}

export interface UserProfile {
  firstName: string;
  lastName: string;
  avatar?: string;
  phone?: string;
  language: SupportedLanguage;
  timezone: string;
  preferences: UserPreferences;
}

export type SupportedLanguage = 'en' | 'pl' | 'de' | 'fr';

export interface UserPreferences {
  theme: 'light' | 'dark' | 'auto';
  notifications: NotificationPreferences;
  accessibility: AccessibilityPreferences;
  dashboard: DashboardPreferences;
}

// =============================================================================
// Onboarding Flow Types
// =============================================================================

export interface OnboardingStatus {
  readonly currentStep: number;
  readonly completedSteps: readonly string[];
  readonly isComplete: boolean;
  readonly startedAt: Date;
  readonly lastActivity: Date;
  readonly progressPercent: number;
  readonly estimatedTimeRemaining: number; // in seconds
  readonly skippedSteps: readonly string[];
}

export interface OnboardingStep {
  readonly id: string;
  readonly title: string;
  readonly description: string;
  readonly component: React.ComponentType<OnboardingStepProps>;
  readonly isOptional: boolean;
  readonly dependencies: readonly string[];
  readonly estimatedTime: number; // in seconds
  readonly helpResources: readonly HelpResource[];
  readonly validation?: OnboardingStepValidation;
  readonly analytics: StepAnalytics;
}

export interface OnboardingStepProps {
  step: OnboardingStep;
  onComplete: (data?: Record<string, any>) => void;
  onSkip?: () => void;
  onError: (error: OnboardingError) => void;
  userData: Partial<AuthUser>;
  isLoading: boolean;
}

export interface OnboardingStepValidation {
  schema: any; // Zod schema
  asyncValidators?: AsyncValidator[];
  crossFieldValidation?: CrossFieldValidator[];
}

export interface AsyncValidator {
  field: string;
  validator: (value: any) => Promise<ValidationResult>;
  debounceMs?: number;
}

export interface CrossFieldValidator {
  fields: string[];
  validator: (values: Record<string, any>) => ValidationResult;
}

export interface ValidationResult {
  isValid: boolean;
  error?: string;
  warnings?: string[];
  suggestions?: string[];
}

// =============================================================================
// Error Handling & Recovery Types
// =============================================================================

export interface OnboardingError {
  readonly type: OnboardingErrorType;
  readonly code: string;
  readonly message: string;
  readonly field?: string;
  readonly recoverable: boolean;
  readonly severity: ErrorSeverity;
  readonly retryAction?: () => Promise<void>;
  readonly helpUrl?: string;
  readonly metadata?: Record<string, any>;
  readonly timestamp: Date;
}

export type OnboardingErrorType =
  | 'validation'
  | 'network'
  | 'server'
  | 'permission'
  | 'timeout'
  | 'rate_limit'
  | 'data_conflict';

export type ErrorSeverity = 'low' | 'medium' | 'high' | 'critical';

export interface ErrorRecoveryStrategy {
  readonly type: 'retry' | 'skip' | 'fallback' | 'reload';
  readonly maxAttempts?: number;
  readonly delayMs?: number;
  readonly fallbackAction?: () => void;
  readonly userMessage: string;
}

