// =============================================================================
// Type Guards
// =============================================================================

export function isValidUserRole(role: string): role is UserRole {
  return ['admin', 'manager', 'operator', 'viewer'].includes(role);
}

export function isOnboardingError(error: any): error is OnboardingError {
  return (
    typeof error === 'object' &&
    error !== null &&
    'type' in error &&
    'code' in error &&
    'message' in error
  );
}

export function isStepComplete(step: OnboardingStep, completedSteps: readonly string[]): boolean {
  return completedSteps.includes(step.id);
}

export function canAccessStep(step: OnboardingStep, completedSteps: readonly string[]): boolean {
  return step.dependencies.every(dep => completedSteps.includes(dep));
}
